text.example:
{
  "artefact_id": "billing-integration-tests",
  "owner": "ruslan@faion.net",
  "django_version": "5.2.1",
  "endpoints": [
    {
      "path": "/api/v1/invoices/",
      "method": "POST",
      "test_cases": ["anonymous-401", "wrong-perm-403", "happy-201", "validation-400"],
      "asserts_body": true
    },
    {
      "path": "/api/v1/invoices/{id}/",
      "method": "GET",
      "test_cases": ["anonymous-401", "happy-200", "not-found-404", "cross-user-403"],
      "asserts_body": true
    }
  ],
  "service_tests": [
    {
      "class_name": "TestInvoiceCreate",
      "scenarios": ["happy_path", "duplicate_number", "negative_amount", "celery_enqueue"],
      "uses_transactional_db": false,
      "boundary_mocks": ["apps.billing.services.send_invoice_email"]
    },
    {
      "class_name": "TestInvoiceVoid",
      "scenarios": ["happy_path", "void_after_paid_raises", "rollback_on_payment_provider_failure"],
      "uses_transactional_db": true,
      "boundary_mocks": ["apps.billing.services.payment_provider"]
    }
  ],
  "ci": {"db_engine": "postgresql", "parallel": true, "coverage_command": "pytest -n auto --cov=apps --cov-report=xml --cov-fail-under=80"},
  "coverage_threshold": 80,
  "version": "1.0.0",
  "last_reviewed": "2026-05-22"
}
